export type TreeNode = {
  name: string;
  path: string;
  type: "file" | "dir";
  children?: TreeNode[] | null;
};

export type AskResponse = {
  path?: string;
  answer?: string;
};

const base = "/api/v1";

export async function fetchProperties(): Promise<string[]> {
  const r = await fetch(`${base}/wiki/properties`);
  if (!r.ok) throw new Error(`properties ${r.status}`);
  return r.json();
}

export async function fetchTree(lie: string): Promise<TreeNode> {
  const r = await fetch(`${base}/wiki/tree?lie=${encodeURIComponent(lie)}`);
  if (!r.ok) throw new Error(`tree ${r.status}`);
  return r.json();
}

export async function fetchFile(path: string): Promise<string> {
  const r = await fetch(`${base}/wiki/file?path=${encodeURIComponent(path)}`);
  if (!r.ok) throw new Error(`file ${r.status}`);
  return r.text();
}

export async function ask(
  question: string,
  lie: string,
): Promise<{ ok: true; data: AskResponse } | { ok: false; status: number }> {
  const r = await fetch(`${base}/ask`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ question, lie }),
  });
  if (!r.ok) return { ok: false, status: r.status };
  return { ok: true, data: await r.json() };
}

export type HumanNotes = { path: string; body: string };

export async function fetchHumanNotes(path: string): Promise<HumanNotes> {
  const r = await fetch(
    `${base}/wiki/human-notes?path=${encodeURIComponent(path)}`,
  );
  if (!r.ok) throw new Error(`human-notes ${r.status}`);
  return r.json();
}

export async function saveHumanNotes(
  path: string,
  body: string,
  pmUser: string,
): Promise<{ path: string; bytes_written: number; commit_sha: string | null }> {
  const r = await fetch(
    `${base}/wiki/human-notes?path=${encodeURIComponent(path)}`,
    {
      method: "PUT",
      headers: {
        "content-type": "application/json",
        "x-pm-user": pmUser,
      },
      body: JSON.stringify({ body }),
    },
  );
  if (!r.ok) {
    const detail = await r.text();
    throw new Error(`human-notes save ${r.status}: ${detail}`);
  }
  return r.json();
}

from __future__ import annotations

from fastmcp import FastMCP


def register_prompts(mcp: FastMCP) -> None:
    @mcp.prompt(
        name="summarize_property",
        description="Summarize the current state of a property in plain language.",
    )
    def summarize_property(property_id: str) -> str:
        return (
            f"You are a Berlin property management assistant. Read the resource "
            f"`property://{property_id}` and summarize: open issues, recent maintenance, "
            f"compliance status, and any owner/tenant items needing follow-up. "
            f"Be concise. Cite section headings."
        )

    @mcp.prompt(
        name="compliance_check",
        description="Run a German legal compliance check on a building.",
    )
    def compliance_check(property_id: str, building_id: str) -> str:
        return (
            f"Read `building://{property_id}/{building_id}`. Cross-check against WEG, "
            f"BauO Bln, BetrSichV obligations. List: (1) overdue items, (2) upcoming "
            f"deadlines in next 90 days, (3) missing documentation. Answer in German "
            f"if the source is in German."
        )

from __future__ import annotations

from fastmcp.exceptions import ToolError
from fastmcp.server.dependencies import get_access_token

from app.mcp.orgs import org_can_access, properties_for_org


def current_org_id() -> str | None:
    token = get_access_token()
    if token is None:
        return None
    claims = getattr(token, "claims", None) or {}
    org_id = claims.get("org_id") or claims.get("organization_id")
    return str(org_id) if org_id else None


def require_org_id() -> str:
    org_id = current_org_id()
    if org_id is None:
        raise ToolError("authenticated token missing org_id claim")
    return org_id


def assert_property_access(property_id: str) -> None:
    org_id = require_org_id()
    if not org_can_access(org_id, property_id):
        raise ToolError(f"org {org_id!r} has no access to property {property_id!r}")


def allowed_properties() -> frozenset[str]:
    return properties_for_org(current_org_id())

from __future__ import annotations

ORG_PROPERTIES: dict[str, frozenset[str]] = {
    "org_buena_berlin": frozenset({"LIE-001"}),
    "org_buena_hamburg": frozenset(),
}


def properties_for_org(org_id: str | None) -> frozenset[str]:
    if org_id is None:
        return frozenset()
    return ORG_PROPERTIES.get(org_id, frozenset())


def org_can_access(org_id: str | None, property_id: str) -> bool:
    return property_id in properties_for_org(org_id)

from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path
from typing import Annotated, Literal

import anyio
from fastapi import Depends

from app.core.config import Settings, get_settings
from app.schemas.buildings import BuildingId
from app.schemas.properties import PropertyId


@dataclass(frozen=True, slots=True)
class TreeNode:
    name: str
    path: str
    type: Literal["file", "dir"]
    children: tuple[TreeNode, ...] | None = None


class WikiService:
    """Reads markdown entries from the property wiki tree."""

    def __init__(self, wiki_dir: Path) -> None:
        self._wiki_dir = wiki_dir

    def _property_path(self, property_id: PropertyId) -> Path:
        return self._wiki_dir / property_id / "index.md"

    def _building_path(self, property_id: PropertyId, building_id: BuildingId) -> Path:
        return self._wiki_dir / property_id / "02_buildings" / building_id / "index.md"

    async def read_property(self, property_id: PropertyId) -> str | None:
        path = self._property_path(property_id)
        if not await anyio.Path(path).is_file():
            return None
        return await anyio.Path(path).read_text(encoding="utf-8")

    async def read_building(self, property_id: PropertyId, building_id: BuildingId) -> str | None:
        path = self._building_path(property_id, building_id)
        if not await anyio.Path(path).is_file():
            return None
        return await anyio.Path(path).read_text(encoding="utf-8")

    def _resolve_safe(self, rel_path: str) -> Path:
        if not rel_path or rel_path.startswith("/") or ".." in Path(rel_path).parts:
            raise ValueError("invalid path")
        full = (self._wiki_dir / rel_path).resolve()
        root = self._wiki_dir.resolve()
        if full != root and root not in full.parents:
            raise ValueError("path escapes wiki_dir")
        return full

    async def read_file(self, rel_path: str) -> str | None:
        full = self._resolve_safe(rel_path)
        if not await anyio.Path(full).is_file():
            return None
        return await anyio.Path(full).read_text(encoding="utf-8")

    def list_properties(self) -> list[str]:
        if not self._wiki_dir.is_dir():
            return []
        return sorted(
            p.name
            for p in self._wiki_dir.iterdir()
            if p.is_dir() and not p.name.startswith(".")
        )

    def walk_tree(self, lie_id: str) -> TreeNode | None:
        root = self._resolve_safe(lie_id)
        if not root.is_dir():
            return None
        return _walk(root, self._wiki_dir.resolve())


def _walk(node: Path, root: Path) -> TreeNode:
    rel = node.relative_to(root).as_posix()
    if node.is_dir():
        children = sorted(
            (c for c in node.iterdir() if not c.name.startswith(".")),
            key=lambda p: (p.is_file(), p.name),
        )
        return TreeNode(
            name=node.name,
            path=rel,
            type="dir",
            children=tuple(_walk(c, root) for c in children),
        )
    return TreeNode(name=node.name, path=rel, type="file")


def get_wiki_service(
    settings: Annotated[Settings, Depends(get_settings)],
) -> WikiService:
    return WikiService(wiki_dir=settings.wiki_dir)

