import { useEffect, useState } from "react";
import { cn } from "../lib/cn";

type Props = {
  onOpenPalette: () => void;
  askEnabled?: boolean;
  askActive: boolean;
  onToggleAsk: () => void;
  treeActive: boolean;
  onToggleTree: () => void;
};

